var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"곤란한 일이라니, 그게 뭐지?","JPN":"困ったことって、何だ？","ENG":"A problem? What is it?","TWN":"麻煩事？什麼麻煩事？"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"실은 등대에 문제가 생겼어.","JPN":"実は、灯台に問題が起きてな。","ENG":"It has to do with the Lighthouse.","TWN":"其實是燈塔出了問題。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"뭐? 그게 무슨 말이지?","JPN":"え？　どういうことだ？","ENG":"What? What do you mean?","TWN":"什麼？什麼意思？"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"분명 공격해 오는 침식체들은 모두 막아냈는데......","JPN":"攻撃してきた侵食体は残さず退治したはずだが……","ENG":"I fended off all the C.O.s I saw.","TWN":"我們明明已經擋下了所有攻過來的侵蝕體……"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"설마 내가 보지 못한 방향에서 기습이라도 당한 건가?","JPN":"まさか死角から奇襲でもうけたのか？","ENG":"Did some of them come from where I couldn't see them?","TWN":"難道是在我沒看到的方向遭到了奇襲？"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"그건 아니야. 당신은 완벽하게 침식체를 막아냈어.","JPN":"そうじゃない。君の侵食体対応は完璧だった。","ENG":"No. You stopped all the C.O.s. There's no doubt about it.","TWN":"不是的，你完美地擋下了侵蝕體。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"하지만 차원 폭풍이 점점 더 강해지고 있는 게 문제야.","JPN":"だが、次元の暴風がさらに勢力を拡大しているのが問題だ。","ENG":"I'm talking about the dimensional storm. It's growing stronger.","TWN":"但問題是次元風暴越來越猛烈了。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"왜 이런 현상이 발생하는지는 모르겠지만, 등대의 부품들이 심하게 부하를 받고 있어.","JPN":"なぜこんな現象が起きているかはわからないが、\\n灯台の部品に強い負荷がかかっている。","ENG":"I don't know why it is, but it's putting a lot of strain on the components of the Lighthouse.","TWN":"雖然不知道為什麼會發生這種現象，但燈塔部件的負荷越來越嚴重了。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"이대로 가다간 곧 등대가 고장 나고 말 거야.","JPN":"このままだと灯台が壊れてしまうだろう。","ENG":"Sooner or later, the Lighthouse will break.","TWN":"再這樣下去，燈塔很快會故障的。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"뭐라고? 막을 수 있는 방법은 없나?","JPN":"何だって？　阻止する方法はないのか？","ENG":"What? Can't we stop it?","TWN":"你說什麼？沒有什麼解決辦法嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"등대가 고장 나면 차원 폭풍 안으로 진입한 소장님이 빠져 나올 수가 없잖아!","JPN":"灯台が壊れたら少将が出られなくなるじゃないか！","ENG":"Without the Lighthouse, the Major General can't find her way out of the dimensional storm.","TWN":"燈塔要是故障，進入次元風暴內部的少將大人不就無法脫離了嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"그러니까 하는 말이지.","JPN":"だから相談してるんだ。","ENG":"That's why I'm talking to you right now.","TWN":"所以我才來和你說這件事。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L15_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"우리도 명색이 정보부 요원들이라고. 여기서 전투식량만 축내고 있던 게 아니야.","JPN":"こう見えて我々も情報局員だからな。ここでただ飯食ってたわけじゃないぞ。","ENG":"We're intelligence agents. We haven't just been sitting here, wasting our combat rations.","TWN":"我們好歹是情報部要員啊，可不只是在這裡浪費戰鬥食糧的。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"분석 결과 차원 폭풍을 증폭시키는 침식 쐐기들이 근처에 포진하고 있어.","JPN":"分析した結果、次元の暴風を拡大させる侵食楔が近くに布陣している。","ENG":"We looked around. There are Corrupted Wedges around here, and they're intensifying the dimensional storm.","TWN":"分析的結果顯示，附近陣列著能使次元風暴增幅的侵蝕釘。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"조금......","JPN":"少し……","ENG":"It may be a little bit—","TWN":"雖然有些……"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L18_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"아니, 매우 위험하긴 하지만 이 침식 쐐기들을 처치할 수만 있다면 차원 폭풍의 강도를 일시적으로 약화시킬 수 있을 거야.","JPN":"いや、非常に危険ではあるがこの侵食楔を排除すれば、次元の暴風の強度を一時的に弱めることができるだろう。","ENG":"Actually, it's going to be very dangerous, but if we take care of these Corrupted Wedges, we can weaken the dimensional storm, though only temporarily.","TWN":"不，雖然非常危險，但只要能解決掉這些侵蝕釘，就能暫時減弱次元風暴的強度。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L19_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"그럼 등대에 가해지는 부하도 조금은 줄어들겠지.","JPN":"そうすれば灯台にかかっている負荷も少しは弱まるはずだ。","ENG":"And that should lessen the burden on the Lighthouse.","TWN":"這樣燈塔的負荷也能減輕了。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"뭐야? 생각보다 간단하잖아?","JPN":"何だ、思ったより簡単じゃないか。","ENG":"What? That's easier than I thought.","TWN":"什麼？這比我想的還要簡單嘛？"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};